## Network Overview

### Partner Distribution by Type


::: {.cell}

```{.r .cell-code}
p_type <- partners |>
  count(type) |>
  ggplot(aes(x = reorder(type, n), y = n, fill = type)) +
  geom_col(width = 0.65, show.legend = FALSE) +
  geom_text(aes(label = n), hjust = -0.3, size = 3.5, colour = "#003781", fontface = "bold") +
  scale_fill_manual(values = c(
    Werkstatt     = "#003781",
    Glaspartner   = "#0066CC",
    Gutachter     = "#00A9CE",
    Abschlepp     = "#66B5E8",
    Mietwagen     = "#FF6600"
  )) +
  scale_y_continuous(expand = expansion(mult = c(0, 0.15))) +
  coord_flip() +
  labs(title    = "Partner Count by Type",
       subtitle = "60 partners across 8 Swiss regions",
       x = NULL, y = "Number of Partners") +
  theme_allianz(grid = "y")

ggplotly(p_type, tooltip = c("x", "y")) |>
  layout(hoverlabel = list(bgcolor = "#003781", font = list(color = "white")))
```

