```{.r .cell-code}
library(visNetwork)

# Nodes: regions (large circles) + partners (smaller dots by type)
region_nodes <- distinct(partners, region) |>
  transmute(
    id         = region,
    label      = region,
    group      = "Region",
    size       = 28,
    font.size  = 14,
    title      = paste0("<b>", region, "</b>")
  )

type_colors <- c(Werkstatt="#0066CC", Glaspartner="#00A9CE",
                  Gutachter="#66B5E8", Abschlepp="#6B7280", Mietwagen="#FF6600")

partner_nodes <- partners |>
  transmute(
    id        = partner_id,
    label     = partner_id,
    group     = as.character(type),
    size      = 12,
    font.size = 9,
    title     = paste0(
      "<b>", name, "</b><br>",
      "Type: ", type, "<br>",
      "Region: ", region, "<br>",
      "Capacity: ", capacity_class
    )
  )

nodes <- bind_rows(region_nodes, partner_nodes)
edges <- partners |>
  select(from = region, to = partner_id) |>
  mutate(color = "#66B5E8", width = 1)

visNetwork(nodes, edges, width = "100%", height = "520px") |>
  visGroups(groupname = "Region",      color = list(background = "#003781", border = "#002060"),
            font     = list(color = "white", size = 14, bold = TRUE)) |>
  visGroups(groupname = "Werkstatt",   color = list(background = "#0066CC",  border = "#004D99")) |>
  visGroups(groupname = "Glaspartner", color = list(background = "#00A9CE",  border = "#007A99")) |>
  visGroups(groupname = "Gutachter",   color = list(background = "#66B5E8",  border = "#3399CC")) |>
  visGroups(groupname = "Abschlepp",   color = list(background = "#6B7280",  border = "#4A4F5A")) |>
  visGroups(groupname = "Mietwagen",   color = list(background = "#FF6600",  border = "#CC5200")) |>
  visOptions(
    highlightNearest = list(enabled = TRUE, degree = 1, hover = TRUE),
    nodesIdSelection = list(enabled = TRUE, main = "Select a partner…",
                            style = "font-size:13px; padding:4px")
  ) |>
  visPhysics(
    solver           = "forceAtlas2Based",
    forceAtlas2Based = list(gravitationalConstant = -60, springLength = 120),
    stabilization    = list(iterations = 200)
  ) |>
  visLegend(width = 0.15, position = "right", main = "Node Type") |>
  visInteraction(tooltipDelay = 100) |>
  visLayout(randomSeed = 42)
