### Funnel by Claim Type


::: {.cell}

```{.r .cell-code}
proc_with_type <- proc_events |>
  left_join(claims |> select(claim_id, claim_type, steering_flag), by = "claim_id")

proc_with_type |>
  arrange(claim_id, timestamp) |>
  group_by(claim_id, claim_type) |>
  mutate(
    days_since_fnol = as.numeric(difftime(timestamp,
                                          timestamp[event_type == "FNOL"],
                                          units = "days"))
  ) |>
  ungroup() |>
  filter(event_type %in% c("RepairEnd", "Closed")) |>
  group_by(claim_type, event_type) |>
  summarise(
    median_days = median(days_since_fnol, na.rm = TRUE),
    .groups     = "drop"
  ) |>
  ggplot(aes(x = claim_type, y = median_days, fill = event_type)) +
  geom_col(position = "dodge", width = 0.65) +
  scale_fill_manual(
    values = c(RepairEnd = "#0066CC", Closed = "#003781"),
    labels = c(RepairEnd = "Repair completed", Closed = "Claim closed"),
    name   = NULL
  ) +
  scale_y_continuous(labels = scales::number_format(suffix = "d")) +
  labs(title    = "Days from FNOL to Key Milestones",
       subtitle = "By claim type · Median across 2021–2024",
       x = "Claim Type", y = "Days since FNOL (median)") +
  theme_allianz()
