## Top / Bottom 10 Partners


::: {.cell layout-ncol="2"}

```{.r .cell-code}
kpis_ranked <- kpis_cost |>
  arrange(cost_zscore)

top10 <- kpis_ranked |>
  slice_head(n = 10) |>
  mutate(highlight = "Top 10 (lowest cost)")

bot10 <- kpis_ranked |>
  slice_tail(n = 10) |>
  mutate(highlight = "Bottom 10 (highest cost)")

plot_ranked <- function(df, title) {
  ggplot(df, aes(x = avg_cost, y = reorder(name, -avg_cost))) +
    geom_segment(aes(xend = mean(kpis$avg_cost), yend = reorder(name, -avg_cost)),
                 colour = "#66B5E8", linewidth = 1.5, linetype = "dashed") +
    geom_point(aes(colour = highlight), size = 4, show.legend = FALSE) +
    geom_vline(xintercept = mean(kpis$avg_cost),
               linetype   = "dashed", colour = "#6B7280", linewidth = 0.5) +
    scale_x_continuous(labels = scales::label_number(prefix = "CHF ", big.mark = ",")) +
    scale_colour_manual(values = c(
      "Top 10 (lowest cost)"    = "#00A9CE",
      "Bottom 10 (highest cost)" = "#FF6600"
    )) +
    labs(title = title, x = "Avg. Repair Cost", y = NULL) +
    theme_allianz(grid = "y")
}

plot_ranked(top10, "Top 10 — Lowest Cost Partners")
