## Steering Rate by Claim Type and Region


::: {.cell}

```{.r .cell-code}
steering_summary <- claims |>
  group_by(claim_type, region) |>
  summarise(pct_steered = mean(steering_flag), .groups = "drop")

p_steer <- ggplot(steering_summary,
                   aes(x = region, y = pct_steered, fill = claim_type)) +
  geom_col(position = "dodge", width = 0.75) +
  scale_fill_manual(
    values = c(glass="#003781", body="#0066CC", engine="#00A9CE", total_loss="#FF6600"),
    name   = "Claim Type"
  ) +
  scale_y_continuous(labels = scales::percent, limits = c(0, 1)) +
  labs(title    = "Steering Rate by Claim Type × Region",
       subtitle = "Proportion of claims routed to network partner",
       x = NULL, y = "Steering Rate") +
  theme_allianz() +
  theme(axis.text.x = element_text(angle = 30, hjust = 1))

ggplotly(p_steer) |>
  layout(legend = list(orientation = "h", y = -0.2))
```

